class Solution {
public:
    int getMinSwaps(string num, int k) {
        int n = num.size();
        string target = num;
        sort(target.begin(), target.end());

        for (int i = 0; i < k - 1; ++i) {
            nextPermutation(target);
        }

        int swaps = 0;
        vector<int> pos(n);
        for (int i = 0; i < n; ++i) {
            pos[num[i] - '0'] = i;
        }

        for (int i = 0; i < n; ++i) {
            if (num[i] != target[i]) {
                int j = pos[target[i] - '0'];
                while (j > i) {
                    swap(num[i], num[j]);
                    pos[num[i] - '0'] = i;
                    pos[num[j] - '0'] = j;
                    swaps++;
                    j = pos[target[i] - '0'];
                }
            }
        }

        return swaps;
    }

    void nextPermutation(string& s) {
        int i = s.size() - 2;
        while (i >= 0 && s[i] >= s[i + 1]) --i;
        if (i < 0) return;

        int j = s.size() - 1;
        while (s[j] <= s[i]) --j;
        swap(s[i], s[j]);

        reverse(s.begin() + i + 1, s.end());
    }
};
